from agent import *from models.products import *import reXCAT = ['Reviews', 'Unboxing', 'Articles', 'Featured']def serialize_text(text):    text = re.sub(r'\[[^\[\]]{1,20}?]', '', text)    # to remove nested brackets    text = re.sub(r'<[^>]+>|\[.*?]', '', text).replace('<', '<').replace('&', '&')    return textdef remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('http://www.funkykit.com/reviews/'), process_revlist, dict())def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//header[@class="entry-header"]')    for rev in revs:        title = rev.xpath('h2/a/text()').string()        url = rev.xpath('h2/a/@href').string()        cats = rev.xpath('span[contains(@class, "cat-links")]/a/text()').strings()        cat = '|'.join(c for c in cats if c not in XCAT)        session.queue(Request(url), process_review, dict(title=title, url=url, cat=cat))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url.replace('dev1.', '')), process_revlist, dict())def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = data.xpath('//div[contains(@class, "review-container")]/*[contains(@class, "review-title")]/text()').string() or context['title'].replace('Review: ', '').replace('Review of the ', '')    if product.name.endswith(' Review'):        product.name = product.name.replace(' Review', '')    product.url = data.xpath('//a[contains(@class, "review-btnbuy")]/@href').string() or context["url"]    product.category = context['cat'] or 'Tech'    product.ssid = context['url'].strip('/').split('/')[-1].replace('-review', '')    product.manufacturer = data.xpath('//div[contains(@class, "penci-review-count")]//div[strong[contains(., "Brand")]]/text()').string()    review = Review()    review.title = context['title']    review.url = context['url']    review.type = 'pro'    review.ssid = product.ssid    date = data.xpath('//meta[contains(@property, "published_time")]/@content').string()    if date:        review.date = date.split('T')[0]    author = data.xpath('//span[contains(@class, "entry-meta-item")]/span/a').first()    if author:        author_name = author.xpath('text()').string()        author_url = author.xpath('@href').string()        author_ssid = author_url.strip('/').split('/')[-1]        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_ssid))    excerpt = data.xpath('(//div[contains(@class, "entry-content")]/p[not(regexp:test(., "(^\s*Conclusion|^\s*Pros|^\s*Cons|^\s*Final word|^\s*Final tho)", "i"))][not(a[contains(@href, "amzn") or contains(@href, "amazon")])][not(contains(., "Related article") or contains(., "More information on"))] | //div[contains(@class, "entry-content")]/blockquote[preceding-sibling::h3[contains(., "Benchmark")]])[not(preceding-sibling::*[contains(., "Verdict") or contains(., "Conclusion") or contains(., "Final Words") or strong[contains(., "Final words")]])]//text()').string(multiple=True)    if excerpt:        excerpt = remove_emoji(excerpt).strip()        if excerpt:            context['excerpt'] = excerpt    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        next_url = next_url.replace('dev1.', '')        page = 1        title = review.title + " - page " + str(page)        review.add_property(type='pages', value=dict(title=title, url=review.url))        session.do(Request(next_url), process_review_next, dict(context, product=product, review=review, page=page+1))    else:        context['product'] = product        context['review'] = review        process_review_next(data, context, session)def process_review_next(data, context, session):    strip_namespace(data)    product = context['product']    review = context['review']    page = context.get('page', 1)    if page > 1:        title = review.title + " - page " + str(page)        review.add_property(type='pages', value=dict(title=title, url=data.response_url))        excerpt = data.xpath('(//div[contains(@class, "entry-content")]/p[not(regexp:test(., "(^\s*Conclusion|^\s*Pros|^\s*Cons|^\s*Final word|^\s*Final tho)", "i"))][not(a[contains(@href, "amzn") or contains(@href, "amazon")])][not(contains(., "Related article") or contains(., "More information on") or contains(., "Verdict") or contains(., "Conclusion") or contains(., "Final Words") or strong[contains(., "Final words")])] | //div[contains(@class, "entry-content")]/blockquote[preceding-sibling::h3[contains(., "Benchmark")]])[not(preceding-sibling::*[contains(., "Verdict") or contains(., "Conclusion") or contains(., "Final Words") or strong[contains(., "Final words")]])]//text()').string(multiple=True)        if excerpt:            excerpt = remove_emoji(excerpt).strip()            if excerpt:                context['excerpt'] = context.get('excerpt', '') + " " + excerpt    pros = data.xpath('//div[contains(@class, "review-good")]/ul/li/text()').strings() or data.xpath('//div[contains(@class, "entry-content")]/ul[preceding-sibling::*[1][self::p[regexp:test(., "^Pro", "i")]]]/li/text()').strings()    for pro in pros:        pro = remove_emoji(pro).strip('*+.-_ ') if pros.count(pro) < 2 else None        if pro and pro not in ['None', 'No', 'Zero', 'Couldn’t find any', "Can't find any"]:            review.add_property(type='pros', value=pro)    cons = data.xpath('//div[contains(@class, "review-bad")]/ul/li/text()').strings() or data.xpath('//div[contains(@class, "entry-content")]/ul[preceding-sibling::*[1][self::p[regexp:test(., "^Con", "i")]]]/li/text()').strings()    for con in cons:        con = remove_emoji(con).strip('*+.-_ ') if cons.count(con) < 2 else None        if con and con not in ['None', 'No', 'Zero', 'Couldn’t find any', "Can't find any"]:            review.add_property(type='cons', value=con)    award = data.xpath('//div[contains(@class, "entry-content")]//img[regexp:test(@src,"(choice|recommend)", "i")]//@src').string()    if award:        review.properties.append(ReviewProperty(type='awards', value=dict(image_src=award)))    grades = data.xpath('//ul[@class="penci-review-number"]/li')    for grade in grades:        grade_name = grade.xpath('.//div[contains(@class, "-point")]/text()').string()        grade_value = grade.xpath('.//div[contains(@class, "-score")]/text()').string()        if grade_name and grade_value:            grade_name = remove_emoji(grade_name).strip('(. )')            grade_value = float(grade_value.replace(',', '.').strip('( )'))            review.grades.append(Grade(name=grade_name, value=grade_value, best=10.0))    grade_overall = data.xpath('//div[contains(@class, "review-score-num")]/text()').string()    if not grade_overall:        grade_overall = data.xpath('//p[strong[contains(., "SCORE")]]/following-sibling::p[1]//text()').string()    if grade_overall:        grade_overall = float(grade_overall.split('/')[0].replace(',', '.').strip())        if grade_overall and grade_overall > 0:            review.grades.append(Grade(type="overall", value=grade_overall, best=10.0))    summary = data.xpath('//div[contains(@class, "penci-review-count")]//div[strong[contains(., "Description")]]/text()[normalize-space()]').string()    if summary:        summary = remove_emoji(summary).strip()        if summary:            review.add_property(type='summary', value=summary)    conclusion = data.xpath('//div[contains(@class, "entry-content")]/p[not(regexp:test(., "(^\s*Conclusion|^\s*Pros|^\s*Cons|^\s*Final word|^\s*Final tho)", "i"))][preceding-sibling::*[contains(., "Verdict") or contains(., "Conclusion") or contains(., "Final Words") or strong[contains(., "Final words")]]][not(contains(., "SCORE"))][not(preceding-sibling::p[contains(., "SCORE")])][not(a[contains(@href, "amzn") or contains(@href, "amazon")])][not(contains(., "Related article") or contains(., "More information on"))][not(strong[regexp:test(., "^\s*Similar") or regexp:test(., "^\s*Silimar")])][not(regexp:test(., "buy", "i") and regexp:test(., "at", "i")) or not(regexp:test(., "can buy", "i") and regexp:test(., "from Amazon", "i"))][not(contains(., "http"))]//text()').string(multiple=True)    if conclusion:        conclusion = remove_emoji(conclusion).strip()        if conclusion:            review.add_property(type='conclusion', value=conclusion)    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        next_url = next_url.replace('dev1.', '')        session.do(Request(next_url), process_review_next, dict(context, page=page+1))    elif context.get('excerpt'):        review.add_property(type="excerpt", value=context['excerpt'].strip())        product.reviews.append(review)        session.emit(product)